mapper.insert:
	INSERT INTO ARMSITE ( SITE_ID
	                    , SITE_NM
	                    , SITE_DESC
	                    , DOMAIN_NM
	                    , TMPLAT_CODE
	                    , META_INFO
	                    , STTUS_CODE
	                    , CHG_USER_ID
	                    , CRT_DATE
	                    , CHG_DATE
	           ) VALUES ( #{siteId}
	                    , #{siteNm}
	                    , #{siteDesc}
	                    , #{domainNm}
	                    , #{tmplatCode}
	                    , #{metaInfo}
	                    , 'A'
	                    , #{UNIQ_ID}
	                    , NOW()
	                    , NOW()
    )

mapper.update:
UPDATE ARMSITE
   SET SITE_NM     = #{siteNm}
     , SITE_DESC   = #{siteDesc}
     , DOMAIN_NM   = #{domainNm}
     , TMPLAT_CODE = #{tmplatCode}
     , META_INFO   = #{metaInfo}
     , CHG_USER_ID = #{UNIQ_ID}
     , CHG_DATE    = NOW()
 WHERE SITE_ID = #{siteId}

UPDATE ARMSITE
   SET STTUS_CODE  = 'D'
     , CHG_USER_ID = #{UNIQ_ID}
     , CHG_DATE    = NOW()
 WHERE SITE_ID = #{siteId}

mapper.select:
SELECT ROW_NUMBER() OVER (ORDER BY A0.SITE_ID DESC) AS RNUM , A0.* FROM (SELECT A1.SITE_ID , A1.SITE_NM , A1.SITE_DESC , A1.DOMAIN_NM , A1.TMPLAT_CODE , A1.META_INFO , COALESCE(A1.SEED_KEY, '') AS SEED_KEY FROM ARMSITE A1 WHERE A1.STTUS_CODE = 'A'
AND A1.SITE_NM LIKE CONCAT('%', #{searchKeyword}, '%')
AND A1.DOMAIN_NM LIKE CONCAT('%', #{searchKeyword}, '%')
) A0 LIMIT #{lengthPage} OFFSET #{startIndex}
